#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 20005
#define MAX_K 35
#define MAX_PI 500005
int N, Q, K, Pi[MAX_N], ci[MAX_N][MAX_PI], base_decomposition[MAX_N];
void dfs(int i, int *visited, int *decomposition) {
    if (visited[i]) return;
    visited[i] = 1;
    if (Pi[i] == 0) decomposition[i] = 1;
    else {
        decomposition[i] = 0;
        for (int j = 0; j < Pi[i]; j++) {
            dfs(ci[i][j], visited, decomposition);
            decomposition[i] ^= decomposition[ci[i][j]];
        }
    }
}
int main() {
    scanf("%d", &N);
    for (int i = 1; i <= N; i++) {
        scanf("%d", &Pi[i]);
        for (int j = 0; j < Pi[i]; j++) {
            scanf("%d", &ci[i][j]);
        }
    }
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        scanf("%d", &K);
        int soups[K];
        for (int j = 0; j < K; j++) {
            scanf("%d", &soups[j]);
        }
        int possible = 0;
        for (int mask = 0; mask < (1 << K); mask++) {
            int decomposition = 0;
            for (int j = 0; j < K; j++) {
                if ((mask & (1 << j))) decomposition ^= base_decomposition[soups[j]];
            }
            for (int submask = 0; submask < mask; submask++) {
                if ((mask & submask) == submask) {
                    int sub_decomposition = 0;
                    for (int j = 0; j < K; j++) {
                        if ((submask & (1 << j))) sub_decomposition ^= base_decomposition[soups[j]];
                    }
                    if (decomposition == sub_decomposition) {
                        possible = 1;
                        break;
                    }
                }
            }
            if (possible) break;
        }
        printf("%d", possible);
    }
    return 0;
}

