        if (visited[i]) return;
        visited[i] = true;
        if (Pi[i] == 0) decomposition[i] = 1;
        else {
            decomposition[i] = 0;
            for (int j = 0; j < Pi[i]; j++) {
                dfs(ci[i][j], visited, decomposition);
                decomposition[i] ^= decomposition[ci[i][j]];
            }
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        N = scanner.nextInt();
        for (int i = 1; i <= N; i++) {
            Pi[i] = scanner.nextInt();
            for (int j = 0; j < Pi[i]; j++) {
                ci[i][j] = scanner.nextInt();
            }
        }
        Q = scanner.nextInt();
        for (int i = 0; i < Q; i++) {
            K = scanner.nextInt();
            int[] soups = new int[K];
            for (int j = 0; j < K; j++) {
                soups[j] = scanner.nextInt();
            }
            int possible = 0;
            for (int mask = 0; mask < (1 << K); mask++) {
                int decomposition = 0;
                for (int j = 0; j < K; j++) {
                    if ((mask & (1 << j)) != 0) decomposition ^= base_decomposition[soups[j]];
                }
                for (int submask = 0; submask < mask; submask++) {
                    if ((mask & submask) == submask) {
                        int sub_decomposition = 0;
                        for (int j = 0; j < K; j++) {
                            if ((submask & (1 << j)) != 0) sub_decomposition ^= base_decomposition[soups[j]];
                        }
                        if (decomposition == sub_decomposition) {
                            possible = 1;
                            break;
                        }
                    }
                }
                if (possible != 0) break;
            }
            System.out.print(possible);
        }
    }
}

